class MyCard extends HTMLElement {
  // 監視する属性
  static observedAttributes = ['title', 'theme'];

  constructor() {
    super();
    this.attachShadow({ mode: 'open' });
  }

  // DOMに追加された時
  connectedCallback() {
    this.render();
  }

  // 属性が変更された時
  attributeChangedCallback(name, oldVal, newVal) {
    if (oldVal !== newVal) this.render();
  }

  // DOMから削除された時
  disconnectedCallback() {
    // クリーンアップ
  }

  render() {
    this.shadowRoot.innerHTML = `
      <style>
        :host { display: block; border: 1px solid #e5e7eb; border-radius: 8px; padding: 1rem; }
        h2 { margin: 0 0 0.5rem; }
      </style>
      <h2>${this.getAttribute('title') || 'カード'}</h2>
      <slot></slot>
    `;
  }
}

customElements.define('my-card', MyCard);

class MyWidget extends HTMLElement {
  constructor() {
    super();
    // Shadow DOMを作成
    const shadow = this.attachShadow({ mode: 'open' });

    // Shadow DOM内のスタイル（外部に漏れない）
    shadow.innerHTML = `
      <style>
        :host {
          display: block;
          font-family: system-ui;
        }
        :host([theme="dark"]) {
          background: #1e293b;
          color: #e2e8f0;
        }
        .title {
          font-size: 1.2rem;
          font-weight: 700;
        }
        /* 外部のCSSはここに影響しない */
      </style>
      <div class="title">
        <slot name="title">デフォルトタイトル</slot>
      </div>
      <slot></slot>
    `;
  }
}
customElements.define('my-widget', MyWidget);

/* Shadow DOM内のスタイル */

/* ホスト要素自体 */
:host {
  display: block;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 1rem;
}

/* ホストが特定のクラスを持つ場合 */
:host(.highlighted) {
  border-color: #3b82f6;
  box-shadow: 0 0 0 3px rgba(59,130,246,0.2);
}

/* ホストの属性に応じたスタイル */
:host([disabled]) {
  opacity: 0.5;
  pointer-events: none;
}

/* 祖先要素のコンテキストに応じたスタイル */
:host-context(.dark-theme) {
  background: #1e293b;
  color: #e2e8f0;
}

