    // カスタムイベントを発火
    this.dispatchEvent(new CustomEvent('item-selected', {
      detail: {
        id: 123,
        name: '選択されたアイテム'
      },
      bubbles: true,     // バブリング有効
      composed: true,     // Shadow DOM境界を越える
      cancelable: true    // キャンセル可能
    }));
  }
}

