class MyTimer extends HTMLElement {
  static observedAttributes = ['interval'];
  #timerId = null;

  // DOM追加時: 初期化・イベント登録
  connectedCallback() {
    this.#start();
    console.log('タイマーコンポーネントが追加されました');
  }

  // DOM削除時: クリーンアップ
  disconnectedCallback() {
    this.#stop();
    console.log('タイマーコンポーネントが削除されました');
  }

  // 属性変更時: 再構築
  attributeChangedCallback(name, oldVal, newVal) {
    if (name === 'interval' && oldVal !== newVal) {
      this.#stop();
      this.#start();
    }
  }

  #start() {
    const ms = parseInt(this.getAttribute('interval')) || 1000;
    this.#timerId = setInterval(() => this.#tick(), ms);
  }

  #stop() {
    if (this.#timerId) clearInterval(this.#timerId);
  }

  #tick() {
    this.textContent = new Date().toLocaleTimeString();
  }
}
customElements.define('my-timer', MyTimer);
